INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1408, 192504, 2, 1053, '客家流沙之落童子', '人有很多理由活着，事情也是。 
<br>     倘若岁月可以收藏如一卷轴，可以选择不同时间流逝的景象，那会是多么安慰人的事！水泥柏油路从平坝到院墟，甚至泥洋、八里坪等村庄的深入，无数的森林便象惭愧的人潮，从山岭隐退。中山河渐渐露出了它粗糙的河床，野狗们可以横渡无忌。山上的野鸡、野猪、野麂、野兔、豺狗、山豹、穿山甲、旱獭、果子狸、巨蟒……它们都静静的消失了，没有一声告白。宽阔的马路上只有汽车喇叭在来回呼啸。明山每年都可以觅得的华南虎行踪， 92年在深坳老杉下拾得它的一颗脱落的病牙后，从此再没人传说虎啸，明山等猎手们也拆卸了所有的长短鸟铳、伏击夜铳，硝盔悬梁。只剩下执迷不悟的兴古，每年秋夏都在水灞汊渠深山涧岩中寻觅为数极少的石�X、圆鱼、沙鳖子，仿佛在挽留过去。 
<br>
<br>      初中生的课文中有一篇《捕蛇者说》，是一个姓柳的大学问家写的，有着高小文化的原泥洋生产队会计刘加良在平坝县医院挂瓶时，百无聊赖，看懂了这篇译文，竟然老泪纵横。又回想起当年自已曾唆使人们，对九一老师那份《关于院墟环境保护的呼吁》文章而且上访章节之事万般嘲弄，且默许半大佬将一颗已泥化的骷髅扔进九一老师的睡房，结果将他的婆娘吓病……一番自责，更是象着了魔，竟对同FANG的病人胡言乱语起来，那病人喊了几声护士却没人回应，便只得蒙被躲藏，谁想凌晨被刺鼻的农药气味和加良疯狂的呻吟声惊醒，恐怖的发现加良扼着脖子倒在地板上翻滚，口吐白沫，床底下阴险的躺着一枚空着的乐果瓶子，居然是服毒自杀了！ 
<br>
<br>      医院大乱，使尽了各种办法，闻声赶到的土地局黄选主任还要求急救医师使用院墟的土法――灌大粪，加良的肚皮被折腾得象吹气球，气息却更迅速的微弱，直到心电图最终成为一条直线时，人们才注意到满地奇怪的碎纸屑。加良的儿子马佬痛不欲生的后悔为什么买了乐果不及时提回去，否则老爹的构端病他就是卖房卖瓦也要治好来的……给加良穿寿衣的矮哥却没肝没肺的嘲笑加良死的时候手指缝中还要死夹着纸片；马佬的小舅婶乌嬷一袭黑衣，远远的站在乌苟树下用抵身裙抹泪――她的姑娘年代只有加良曾送过她礼物，一片美俊的木梳。她红肿的眼光扫荡着土楼周围的一切细节：那些头上戴着白孝的人们，瓦檐栖落的蜻蜓，一阵凉嗖嗖的阴风……忽然，她毛骨悚然的捂上了嘴，因为她看到那巨大的黑棺上竟然有两只草蜢，一大一小，大的已青皮转黑，小的则青翠碜人，趴在那大的背上，在黑棺上蹒跚而行…… 
<br>
<br>      ――许多人在乌嬷家落童子时，经提醒蓦然回想起来，好象那棺上的确有草蜢，只是一只或两只或是在棺上还是龙索上则是众说纷纭了。 
<br>  
<br>      对于一切意外和天灾人祸，中国人都习惯归结于命运使然。破四旧工作队进驻八里坪的时候，民选安排了他们住在位于山头岗的小学里，当晚窗棂毕剥，淡蓝的磷火在荒野的黑暗中漂移，许多人都被一丝若有若无的哭泣声惊起，其中一人识相，把伙头的所有家伙：锄头、耘耙、锅铲、漏勺、盆具都抛出门去，这才战战兢兢的盼来天亮，逃跑得连命都可以不要了。院墟人对任何奇特的事，有他们独特的破解方法。――乌嬷在落童子的时候为泥洋人解答了一切疑惑。 
<br>
<br>      落童子最适宜在交春之时，此时阴阳交接，人鬼换班，神灵失效，有无数的院墟人可以证明，在交春那一分钟，一个生鸡蛋居然能站立起来！仿佛有看不见的手把它扶住了，而时间一到，那鸡蛋便会倒回桌上，毫无生气的滚动。这会让所有不信邪的青皮后生毛孔直竖。接着，披头散发的乌嬷便在众目睽睽中取出装满米的竹升筒，焚上三支高香，清醒的认证桌上趴的人的生肖――生肖不符的人若去了阴间易受鬼魂暗算。趴在桌上的人要头伏双臂，心无杂念。乌嬷在烟雾缭绕中开始得神作法，经过一阵时间的“嗨――哎”长长叹谓后，便低眉垂眼的吟唱着歌词，唤开阴间的土层，不用多久，桌上趴的人中便会有人全身开始剧烈颤抖，全身性的筛抖，从脚臀到头颈的细微连动，而且是坐在板凳上，任何舞者都无法模仿，力气大的男子曾有将桌掀翻过。有时是一人有此症状，有时则是两三人同时元神出窍，乌嬷便有所选择，如体虚的，或年纪小的，便用掌连击其后心三下，拍醒过来。剩下一人便孤独的继续前行，乌嬷不断的吟唱，“黄泥岔道收住脚，白沙路上袅袅去”，提醒正往阴间飘去的灵魂不要胆怯也不要贪恋，有阳神在护佑，只管朝前不要回头。有时，落童子的人会害怕叫喊，说有很多鬼拦路，不让前进，乌嬷便赶紧烧备好的纸钱，指挥落童子的人乘它们抢钱时跑过去。这关一过，有两名童子出现，并会缠着落童子的人胡闹，乌嬷教落童子的人又哄又骗，待童子开心，或者累得睡眠了，这才能进入另一重环境。不用多久，落童子的人无一例外的会再度惊恐，甚至哭出声来，说有一只好大的凶狗守着门，乌嬷便让落童子的DA声喊六一公公、六一婆婆，赶快来帮我把狗逐开――若旁听有好奇的人，乌嬷还能让落童子的人告诉大家六一公公、六一婆婆慈眉善目的长相。进了那道门，却是一个美丽的大花园，开满了无数鲜花，令落童子的人留恋忘返，乌嬷看看高香焚烧的进度，便会厉声喝醒那迷醉的人，赶快穿过花园去办正经事――这时，才是落童子的最要紧环节。 
<br>
<br>       落童子的人时哭时笑，时而惊惶失措，时而嬉笑开颜。头却是一刻都没离开伏着的双臂的，颤抖如咆哮的，经过花园后，一般都能稍稍平静下来，乌嬷便让人取了干毛巾，为落童子的人的湿发和脖颈擦拭。旁边有疑惑事的人便开始发问了，无法直接问，只能由乌嬷来转达，问题完全可以突破时间和空间的局限。如加良，把它从坟墓召来时，它撑着拐杖一路哭泣，路过别的鬼的坟墓时，因它们嫌弃它是个吃药死的短命鬼，一直暴喝快滚开，有的还用长长的皮鞭抽得落童子的人团着身尖叫，它呜咽着告诉亲人们它喝乐果的原因是因为前一个月死在那病房的女鬼的捉弄，它现在浑身乐果臭味，带下世的寿衣都被其他鬼抢了去，被它们排斥欺辱，受饥挨饿，在阴间忍受无尽的孤独……加良的婆娘银招嬷坐在板凳上听了，咬着牙压低声音，哭得浑身泪水。 
<br>
<br>      又如观音生淹死在中山河的小儿子，附身在落童子的人身上，一张嘴便哭喊着爸妈我不想死啊，是糍粑客藏在深潭里，突然窜出来把我拖下水底的……观音生气愤填膺，但敌人却是死去十几年且尸骨无踪的水鬼，无可报仇，便气憋憋的要糍粑客来质问。人们等了很久，落童子的人悄无声息，好象睡熟过去，这时有人想问别的事情了，不料落童子的人却幽幽的一声叹息，吐了一句水底好凉啊！让所有的人都起了一层鸡皮疙瘩，乌嬷便开始问它，它一会儿说的是难听的福佬话，一会儿又是夹生的客家话，经过与知青最合群的火金生的翻译，总算听懂了它的意思，说是它被招到水底作中山河的鬼差了，年年都是要一个人到水里去替身的，劝大家管好自已的孩子，不要让他们被它碰上，不然它也是难做的。观音生一直想插上嘴骂它几句的，不料到后来，那鬼却胡言乱语起来，都是说它的厦门话，除了妈妈两个字依稀明白外，其它的都是尖锐的厮喊和哭泣声了。再没一个人敢吭声，它临走前说了一句清醒话，说是有一个矮古古的人把它的蓑衣捡走了。 
<br>
<br>       还有才秀嬷打柴摔伤了，是一个满山窜的凶死鬼使的绊腿，需取了她的内衣黄昏时送它到三岔路口去烧；石秀古的小女孩子老是半夜啼哭，是因为他世下的老娘太关心家里，经常在半夜从蚊帐顶探下头来看望，而不会说话的小孩就象狗是能见鬼的，要石秀古赶快多烧冥币，通知老娘别再殷勤；茂荣家之所以绝户，是因为他家移祖坟时没请好了风水先生，他好心拼大风水反地煞不成功，反被阎王将一家五口连同算命先生都葬身在山体滑坡中。 
<br>
<br>       ………… 
<br>
<br>       死去的人仍是凶手，这是落童子的普遍逻辑。任何隐密的事情，在此时都变成了可怕的透明，而对虚无的存在，人们没勇气撒谎。它能解答世间活着的人想破脑壳也无法确定的事实，还会提醒人们今后要注意的事情，或躲难避祸之法――虽然悲剧永远都正在发生。但很多疑窦是无法细问的，只能靠你自已去想象，补充完整。整个过程在一种诡密的气氛中完成，一旦香火快燃尽，乌嬷必须把落童子的人拍醒，否则指路的香烟一散，他（她）的魂魄便会永远迷失方向，寻不回来。坑背的大薯妹便是一个活例证，闷了心肝七八年，说话疯疯颠颠，六亲不认，幸好有一天被出嫔时的孝子碗碎片弹中心窝，这才误打误着清醒过来。 
<br>
<br>        很多有文化的人轻蔑落童子是一个俗不可耐的迷信玩意，并用许多例如梦魇、催眠术等科学道理来论证他们的正确。但另一方面，他们又常常对着神玳山上那头被镇的神龟长叹不已。碰上较真的，刚好又遇上了落童子的好季节，而乌嬷又心情朗爽时，便想亲身试验落童子的真实，亦或魔幻。也随着其他人双手交叠伏在木桌上，闻着香火的刺鼻，听乌嬷咿呀吟唱，却是永远也去不成的，因为他的心大部分时间都在思索别人，或时不时抬起头来看他人的状态，有了文化教育，便永远也无法象别人那样心无杂念。当有落童子的人开始颤抖，并飘然于阴间，各种不同的鬼魂应召附其身，述说离奇而又真实的迷惑时，轻蔑便比焚尽的香灰还不堪一击。 
<br>
<br>        乌嬷是个脾气暴躁的女人，做过许多比男人还烈性的事。但落童子等巫术，却只有她和其它几名妇人才擅长。人们在农闲时热衷于此，如同打蘸扛菩萨、走古事、舞狮、打船灯……但大一统的文明随公路的扩展推进，电视音响全面入侵，这些仿佛愚陋的精彩便渐渐的没落了――除了些宣传性的官方活动。后来，有台湾佬回八里坪省亲，带回一副麻将，象病毒般传染，院墟便被麻将声淹没了，落童子仅仅是一些顽固不化的老妪们在接力。再后来，“六叔公”进入院墟，高利润的赌局将所有农民的心俘虏。愈演愈烈，公AN部门几番出动大批警力，六合迷们却利用山岗田野打游击，无法遏止，几乎所有的人都已痴迷于生肖、特码、单双、红蓝绿波……敛财之心将人们一切理智清洗。因为乌嬷曾�e幸中过两期，她便成了六合迷们心中的财神。每天都有无数辆摩托车停在她家门口，一双双沾着泥巴的脚，带着水田中的泥腥，迫不及待的走进去……', '人有很多理由活着，事情也是。

倘若岁月可以收藏如一卷轴，可以选择不同时间流逝的景象，那会是多么安慰人的事！水泥柏油路从平坝到院墟，甚至泥洋、八里坪等村庄的深入，无数的森林便象惭愧的人潮，从山岭隐退。中山河渐渐露出了它粗糙的河床，野狗们可以横渡无忌。山上的野鸡、野猪、野麂、野兔、豺狗、山豹、穿山甲、旱獭、果子狸、巨蟒……它们都静静的消失了，没有一声告白。宽阔的马路上只有汽车喇叭在来回呼啸。明山每年都可以觅得的华南虎行踪， 92年在深坳老杉下拾得它的一颗脱落的病牙后，从此再没人传说虎啸，明山等猎手们也拆卸了所有的长短鸟铳、伏击夜铳，硝盔悬梁。只剩下执迷不悟的兴古，每年秋夏都在水灞汊渠深山涧岩中寻觅为数极少的石�X、圆鱼、沙鳖子，仿佛在挽留过去。

